class Solution {
    public List<Long> maximumEvenSplit(long finalSum) {
        List<Long> result = new ArrayList<>();
        if (finalSum % 2 != 0) return result;
        long i = 2;
        while (finalSum > 0 && i <= finalSum) {
            if (!result.contains(i)) {
                result.add(i);
                finalSum -= i;
            }
            i += 2;
        }
        if (finalSum != 0) return new ArrayList<>();
        return result;
    }
}
